SELECT ?club ?losses WHERE {
  ?club p:P1092 [
    ps:P1092 wd:Q1285952;
    pq:P580 ?start;
    pq:P582 ?end
  ].
  FILTER ( (YEAR(?start) <= 1913 && YEAR(?end) >= 1913) || (YEAR(?start) <= 1944 && YEAR(?end) >= 1944) ).
  ?club wdt:P3347 ?losses.
}
ORDER BY ?losses
LIMIT 2

